      engineStatus[`${id}:score`] = '0';
      const errMsg = String(event.data?.error ?? 'failed');
      engineStatus[`${id}:error`] = errMsg;
      const snippet = errMsg.length > 120 ? errMsg.slice(0, 120) + '…' : errMsg;
      dispatch({ type: 'warning', message: `${id} failed: ${snippet}` });
